import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { OrdersService } from '../../core/services/orders.service';
import { Order, OrderStatus } from '../../core/models';
import { MoneyPipe } from '../../shared/money.pipe';

@Component({
  selector: 'app-admin-orders',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './admin-orders.component.html',
  styleUrls: ['./admin-orders.component.css'],
})
export class AdminOrdersComponent {
  private ordersSvc = inject(OrdersService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly filters: Array<{ key: string; label: string }> = [
    { key: '', label: 'All' },
    { key: 'placed', label: 'Placed' },
    { key: 'shipped', label: 'Shipped' },
  ];

  readonly statusFilter = toSignal(this.route.queryParamMap.pipe(map((p) => p.get('status') ?? '')), {
    initialValue: '',
  });

  readonly orders = computed<Order[]>(() => {
    const status = this.statusFilter();
    const all = this.ordersSvc.orders();
    return status ? all.filter((o) => o.status === (status as OrderStatus)) : all;
  });

  setFilter(status: string): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { status: status || null },
      queryParamsHandling: 'merge',
    });
  }

  advance(id: string): void {
    this.ordersSvc.advanceStatus(id);
  }
}
